       onFocus: show,
       onMouseEnter: show,
       onMouseLeave: hide,
     }
   );

   return (
     <>
       <span
         ref={anchorRef}
         className={cn("relative inline-flex align-middle", wrapperClassName)}
       >
         {trigger}
